function runPreParsing (err, request, reply) {
  if (reply.sent === true) return
  if (err != null) {
    reply[kReplyIsError] = true
    reply.send(err)
    return
  }

  request[kRequestPayloadStream] = request.raw

  if (request[kRouteContext].preParsing !== null) {
    preParsingHookRunner(request[kRouteContext].preParsing, request, reply, handleRequest.bind(request.server))
  } else {
    handleRequest.call(request.server, null, request, reply)
  }
}

render () {
  const {isFetching, tweets} = this.props
  if (isFetching) return <div>Loading tweets...</div>

  const tweetForm = <TweetForm onNewTweet={text => this.props.onNewTweet(text)} />
  const tweetStream = <TweetList tweets={tweets} />
  const noTweetsBanner = tweets.length === 0
    ? <div className='mui--text-center mui--text-dark mui--text-body2'>No tweet available, let is stating to write one!</div>
    : ''

  return <div>
    {tweetForm}
    {tweetStream}
    {noTweetsBanner}
  </div>
}

Boot.prototype.onClose = function (func) {
  // this is used to distinguish between onClose and close handlers
  // because they share the same queue but must be called with different signatures

  if (typeof func !== 'function') {
    throw new AVV_ERR_CALLBACK_NOT_FN('onClose', typeof func)
  }

  func[kIsOnCloseHandler] = true
  this._closeQ.unshift(func, (err) => { err && (this._error = err) })

  return this
}

function buildRoutePrefix (instancePrefix, pluginPrefix) {
  if (!pluginPrefix) {
    return instancePrefix
  }

  // Ensure that there is a '/' between the prefixes
  if (instancePrefix.endsWith('/') && pluginPrefix[0] === '/') {
    // Remove the extra '/' to avoid: '/first//second'
    pluginPrefix = pluginPrefix.slice(1)
  } else if (pluginPrefix[0] !== '/') {
    pluginPrefix = '/' + pluginPrefix
  }

  return instancePrefix + pluginPrefix
}

function safeWriteHead (reply, statusCode) {
  const res = reply.raw
  try {
    res.writeHead(statusCode, reply[kReplyHeaders])
  } catch (err) {
    if (err.code === 'ERR_HTTP_HEADERS_SENT') {
      reply.log.warn(`Reply was already sent, did you forget to "return reply" in the "${reply.request.raw.url}" (${reply.request.raw.method}) route?`)
    }
    throw err
  }
}

handler: function(routeOptions, route) {
  return async function(request: FastifyRequest): Promise<void> {
    const allowedMethods = getAllowedMethods(this.config);
    const handlerKey = Object.keys(routeOptions).find(
      (key) =>
        routeOptions[key].method === request.routerMethod &&
        routeOptions[key].url === request.routerPath.replace(route || '/', '')
    );

    if (handlerKey && !allowedMethods.includes(handlerKey as any)) {
      throw createError(405, `Method ${request.routerMethod} is not allowed here`);
    }
  };
}

function isValidSchema (schema, name) {
  if (!validate(schema)) {
    if (name) {
      name = `"${name}" `
    } else {
      name = ''
    }
    const first = validate.errors[0]
    const err = new Error(`${name}schema is invalid: data${first.instancePath} ${first.message}`)
    err.errors = isValidSchema.errors
    throw err
  }
}

const main = async () => {
  fastify = await runFastify(process.argv.splice(2))
  const type = process.env.childEvent

  process.send({ type, err: null })

  try {
    await fastify.ready()
    process.send({ type: READY })
  } catch (err) {
    stop(err)
  }
}

function checkDependencies (fn) {
  const meta = getMeta(fn)
  if (!meta) return

  const dependencies = meta.dependencies
  if (!dependencies) return
  assert(Array.isArray(dependencies), 'The dependencies should be an array of strings')

  dependencies.forEach(dependency => {
    if (!this[kRegisteredPlugins].includes(dependency)) {
      throw new FST_ERR_PLUGIN_DEPENDENCY_NOT_REGISTERED(dependency, meta.name)
    }
  })
}

function handlePressure (pressureHandler, req, reply, next, type, value) {
  if (typeof pressureHandler === 'function') {
    const result = pressureHandler(req, reply, type, value)
    if (result instanceof Promise) {
      result.then(() => next(), next)
    } else if (result == null) {
      next()
    } else {
      reply.send(result)
    }
  } else {
    reply.status(SERVICE_UNAVAILABLE).header('Retry-After', retryAfter)
    next(underPressureError)
  }
}

makeRegister = ({email, username, password}) => dispatch => {
  dispatch(doingRegister())
  return axios.post('/api/user/register', { email, username, password })
    .then((response) => response.data)
    .then(body => {
      dispatch(push('/login'))
      return dispatch(registerSuccess(body))
    })
    .catch(error => dispatch(registerFailed(error)))
}

function createSSREnvironment(dev: boolean, outDir: string, clientModule: string) {
  return {
    build: {
      outDir: `${outDir}/server`,
      ssr: true,
      minify: !dev,
      sourcemap: dev,
      emitAssets: true,
      rollupOptions: {
        input: {
          index: clientModule,
        },
      },
    },
  }
}

function hookFactory(event: ControllerHooks) {
  return function(target: object, propertyKey: string): void {
    Reflect.defineMetadata('fastify-resty:hook', { event }, target, propertyKey);

    if (Reflect.hasMetadata('fastify-resty:hooks', target)) {
      const hooks: Set<string> = Reflect.getMetadata('fastify-resty:hooks', target);
      hooks.add(propertyKey);
    } else {
      Reflect.defineMetadata('fastify-resty:hooks', new Set([ propertyKey ]), target);
    }
  }
}

async remove(request: FastifyRequest<{ Querystring: IFindWhereQuery | { $results: boolean } }>) {
  const response: any = {};

  if (get(request.query.$results, this.config.returning)) {
    response.data = await this.model.find({ $where: request.query });

    if (!response.data.length) {
      return { affected: 0, data: [] };
    }
  }

  const { affected } = await this.model.remove(request.query);
  response.affected = affected;

  return response;
}

async updateOne(request: FastifyRequest<{ Params: { id: Identifier; }, Body: Entity, Querystring: { $results: boolean } }>) {
  const { params: { id }, query: { $results } } = request;
  const { affected } = await this.model.update({ [this.config.id]: id }, request.body);

  if (get($results, this.config.returning)) {
    const result = await this.model.find({ $where: { [this.config.id]: id } });
    return result[0];
  }

  return { affected };
}

asNumber (i) {
  // fast cast to number
  const num = Number(i)
  // check if number is NaN
  // eslint-disable-next-line no-self-compare
  if (num !== num) {
    throw new Error(`The value "${i}" cannot be converted to a number.`)
  } else if (num === Infinity || num === -Infinity) {
    return 'null'
  } else {
    return '' + num
  }
}

function createChildLogger (context, logger, req, reqId, loggerOpts) {
  const loggerBindings = {
    [context.requestIdLogLabel]: reqId
  }
  const child = context.childLoggerFactory.call(context.server, logger, loggerBindings, loggerOpts || {}, req)

  // Optimization: bypass validation if the factory is our own default factory
  if (context.childLoggerFactory !== defaultChildLoggerFactory) {
    validateLogger(child, true) // throw if the child is not a valid logger
  }

  return child
}

function ajvFilePlugin (ajv) {
  return ajv.addKeyword({
    keyword: 'isFile',
    compile: (_schema, parent) => {
      // Updates the schema to match the file type
      parent.type = 'string'
      parent.format = 'binary'
      delete parent.isFile

      return (field /* MultipartFile */) => !!field.file
    },
    error: {
      message: 'should be a file'
    }
  })
}

async function viewLiquid (page, data, opts) {
  data = Object.assign({}, defaultCtx, this.locals, data)
  let render
  if (typeof page === 'string') {
    // Append view extension.
    page = getPage(page, 'liquid')
    render = engine.renderFile.bind(engine, join(templatesDir, page))
  } else if (typeof page === 'function') {
    render = page
  } else if (typeof page === 'object' && page.raw) {
    const templates = engine.parse(page.raw)
    render = engine.render.bind(engine, templates)
  }

  return render(data, opts)
}

function validateInitialConfig (options) {
  const opts = deepClone(options)

  if (!validate(opts)) {
    const error = new FST_ERR_INIT_OPTS_INVALID(JSON.stringify(validate.errors.map(e => e.message)))
    error.errors = validate.errors
    throw error
  }

  return deepFreezeObject(opts)
}

function buildContentTypeParser (c) {
  const contentTypeParser = new ContentTypeParser()
  contentTypeParser[kDefaultJsonParse] = c[kDefaultJsonParse]
  contentTypeParser.customParsers = new Map(c.customParsers.entries())
  contentTypeParser.parserList = c.parserList.slice()
  contentTypeParser.parserRegExpList = c.parserRegExpList.slice()
  return contentTypeParser
}

function logStreamError (logger, err, res) {
  if (err.code === 'ERR_STREAM_PREMATURE_CLOSE') {
    if (!logger[kDisableRequestLogging]) {
      logger.info({ res }, 'stream closed prematurely')
    }
  } else {
    logger.warn({ err }, 'response terminated with an error with headers already sent')
  }
}

setupSerializer (serverOptions) {
  const isReady = this.serializerCompiler !== undefined && !this.addedSchemas
  if (isReady) {
    return
  }

  this.serializerCompiler = this.getSerializerBuilder()(this.schemaBucket.getSchemas(), serverOptions.serializerOpts)
}

async prepareClient(entries: ClientEntries) {
  const clientModule = entries.ssr
  if (!clientModule) {
    return null
  }
  const routes =
    typeof clientModule.routes === 'function' ? await clientModule.routes() : clientModule.routes
  return Object.assign({}, clientModule, { routes })
}

function checkIfIsTrusted (result, callback) {
  if (!trusted) {
    callback(null, result)
  } else {
    const maybePromise = trusted(request, result)

    if (maybePromise?.then) {
      maybePromise
        .then(trusted => trusted ? callback(null, result) : callback(new AuthorizationTokenUntrustedError()))
    } else if (maybePromise) {
      callback(null, result)
    } else {
      callback(new AuthorizationTokenUntrustedError())
    }
  }
}

createErrorHandler(
  _args: ClientRouteArgs,
  _scope: FastifyInstance,
  config: RuntimeConfig,
): NonNullable<RouteOptions['errorHandler']> {
  return (error, req, reply) => {
    if (config.dev) {
      console.log(error)
      reply.code(500).type('application/json').send(JSON.stringify({ error }))
    } else {
      reply.code(500).send('')
    }
  }
}

export function hasIterableRoutes(
  client: unknown,
): client is ClientModule & { routes: Iterable<RouteDefinition> } {
  if (!client || typeof client !== 'object') return false
  const maybeClient = client as { routes?: unknown }
  const routes = maybeClient.routes
  return (
    !!routes &&
    typeof routes !== 'string' && // strings are iterable, but not desired here
    typeof (routes as Iterable<unknown>)[Symbol.iterator] === 'function'
  )
}

function getEncodingHeader (headers, checked) {
  if (!('accept-encoding' in headers)) return

  // consider the no-preference token as gzip for downstream compat
  const header = headers['accept-encoding'].toLowerCase().replace(asteriskRegex, 'gzip')

  return encodingNegotiator.negotiate(
    header,
    supportedEncodings.filter((enc) => !checked.has(enc))
  )
}

function resolveSchemaReference (rawSchema, ref) {
  const resolvedReference = ref.resolve(rawSchema, { externalSchemas: [ref.definitions().definitions] })

  // Ref has format `#/definitions/id`
  const schemaId = resolvedReference?.$ref?.split('/', 3)[2]

  if (schemaId === undefined) {
    return undefined
  }

  return resolvedReference.definitions?.[schemaId]
}
